import { EmptyState } from '@/components/ui'
import { BookOpen } from 'lucide-react'

export function LearningPage() {
  return (
    <div className="p-6">
      <EmptyState
        title="Learning"
        description="Your active and completed lessons will appear here."
        icon={<BookOpen className="h-12 w-12" />}
      />
    </div>
  )
}

import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { apiClient } from '@/api/client'
import type {
  DashboardSummary,
  TopicProgress,
  Recommendation,
  LearningStreak,
  LearningPath,
  Lesson,
  LessonRequest,
  Quiz,
  QuizGenerateRequest,
  EvaluateRequest,
  EvaluateResult,
  SyllabusGraph,
  AdaptiveStatus,
  WeakConcepts,
  SessionData,
} from '@/types/learning'

// ─── Dashboard Hooks ──────────────────────────────────────────

export function useDashboard() {
  return useQuery<DashboardSummary>({
    queryKey: ['dashboard'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/dashboard')
      return data
    },
  })
}

export function useTopicProgress() {
  return useQuery<TopicProgress[]>({
    queryKey: ['dashboard', 'progress'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/dashboard/progress')
      return data
    },
  })
}

export function useRecommendations() {
  return useQuery<Recommendation[]>({
    queryKey: ['dashboard', 'recommendations'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/dashboard/recommendations')
      return data
    },
  })
}

export function useLearningStreak() {
  return useQuery<LearningStreak>({
    queryKey: ['dashboard', 'streak'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/dashboard/streak')
      return data
    },
  })
}

// ─── Knowledge Graph / Roadmap Hooks ──────────────────────────

export function useSyllabusGraph(syllabusId: string) {
  return useQuery<SyllabusGraph>({
    queryKey: ['knowledge-graph', syllabusId],
    queryFn: async () => {
      const { data } = await apiClient.get(`/api/v2/knowledge-graph/${syllabusId}`)
      return data
    },
    enabled: !!syllabusId,
  })
}

export function useLearningPath(
  syllabusTopicIds: string[],
  masteryScores: Record<string, number> = {},
  mode: string = 'standard'
) {
  return useQuery<LearningPath>({
    queryKey: ['learning-path', { syllabusTopicIds, masteryScores, mode }],
    queryFn: async () => {
      const { data } = await apiClient.post('/api/v2/knowledge-graph/learning-path', {
        syllabus_topic_ids: syllabusTopicIds,
        mastery_scores: masteryScores,
        mode,
      })
      return data
    },
    enabled: syllabusTopicIds.length > 0,
  })
}

// ─── Lesson Hooks ─────────────────────────────────────────────

export function useGenerateLesson() {
  return useMutation({
    mutationFn: async (request: LessonRequest) => {
      const { data } = await apiClient.post<Lesson>('/api/v2/lessons/lesson', request)
      return data
    },
  })
}

// ─── Quiz Hooks ───────────────────────────────────────────────

export function useGenerateQuiz() {
  return useMutation({
    mutationFn: async (request: QuizGenerateRequest) => {
      const { data } = await apiClient.post<Quiz>('/api/v2/quiz/generate', request)
      return data
    },
  })
}

export function useEvaluateQuiz() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (request: EvaluateRequest) => {
      const { data } = await apiClient.post<EvaluateResult>('/api/v2/quiz/evaluate', request)
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['dashboard'] })
    },
  })
}

// ─── Adaptive Hooks ───────────────────────────────────────────

export function useAdaptiveStatus() {
  return useQuery<AdaptiveStatus>({
    queryKey: ['adaptive', 'status'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/adaptive/status')
      return data
    },
  })
}

export function useWeakConcepts(
  masteryScores: Record<string, number>,
  currentTopicId?: string
) {
  return useQuery<WeakConcepts>({
    queryKey: ['adaptive', 'weak-concepts', { masteryScores, currentTopicId }],
    queryFn: async () => {
      const { data } = await apiClient.post('/api/v2/knowledge-graph/weak-concepts', {
        mastery_scores: masteryScores,
        current_topic_id: currentTopicId,
      })
      return data
    },
    enabled: Object.keys(masteryScores).length > 0,
  })
}

// ─── Session Hooks ────────────────────────────────────────────

export function useCreateSession() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (params: { syllabus_id?: string; session_id?: string; metadata?: Record<string, unknown> }) => {
      const { data } = await apiClient.post<SessionData>('/api/v2/sessions', params)
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['sessions'] })
    },
  })
}

export function useSession(sessionId: string) {
  return useQuery<SessionData>({
    queryKey: ['sessions', sessionId],
    queryFn: async () => {
      const { data } = await apiClient.get(`/api/v2/sessions/${sessionId}`)
      return data
    },
    enabled: !!sessionId,
  })
}

export function useCompleteSession() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (sessionId: string) => {
      const { data } = await apiClient.post(`/api/v2/sessions/${sessionId}/complete`)
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['sessions'] })
      queryClient.invalidateQueries({ queryKey: ['dashboard'] })
    },
  })
}

import { type ReactNode } from 'react'
import { cn } from '@/utils/cn'

interface CardProps {
  children: ReactNode
  className?: string
  hover?: boolean
  padding?: 'sm' | 'md' | 'lg'
}

const paddings = {
  sm: 'p-4',
  md: 'p-6',
  lg: 'p-8',
}

export function Card({ children, className, hover = false, padding = 'md' }: CardProps) {
  return (
    <div
      className={cn(
        'bg-surface border border-surface-border rounded-lg shadow-card transition-all duration-200',
        hover && 'hover:border-primary/30 hover:shadow-glow cursor-pointer',
        paddings[padding],
        className
      )}
    >
      {children}
    </div>
  )
}

import { forwardRef, type ButtonHTMLAttributes } from 'react'
import { cn } from '@/utils/cn'
import { Loader2 } from 'lucide-react'

interface ButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost' | 'danger'
  size?: 'sm' | 'md' | 'lg'
  loading?: boolean
  icon?: React.ReactNode
}

const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant = 'primary', size = 'md', loading, icon, children, disabled, ...props }, ref) => {
    const baseStyles =
      'inline-flex items-center justify-center gap-2 font-body font-medium transition-all duration-200 focus-visible:outline-2 focus-visible:outline-primary focus-visible:outline-offset-2 disabled:opacity-50 disabled:cursor-not-allowed'

    const variants = {
      primary:
        'bg-primary text-text-inverse hover:bg-primary-hover active:bg-primary shadow-sm',
      secondary:
        'bg-surface border border-surface-border text-text-primary hover:bg-surface-hover active:bg-surface-border',
      ghost:
        'bg-transparent text-text-secondary hover:bg-surface-hover hover:text-text-primary',
      danger:
        'bg-danger text-white hover:bg-danger-hover',
    }

    const sizes = {
      sm: 'h-8 px-3 text-xs rounded-md',
      md: 'h-10 px-4 text-sm rounded-md',
      lg: 'h-12 px-6 text-base rounded-lg',
    }

    return (
      <button
        ref={ref}
        disabled={disabled || loading}
        className={cn(baseStyles, variants[variant], sizes[size], className)}
        {...props}
      >
        {loading ? <Loader2 className="h-4 w-4 animate-spin" /> : icon}
        {children}
      </button>
    )
  }
)

Button.displayName = 'Button'

export { Button }
export type { ButtonProps }

import { cn } from '@/utils/cn'

interface BadgeProps {
  children: React.ReactNode
  variant?: 'default' | 'primary' | 'secondary' | 'success' | 'danger'
  size?: 'sm' | 'md'
  className?: string
}

const variants = {
  default: 'bg-surface-border text-text-secondary',
  primary: 'bg-primary-muted text-primary',
  secondary: 'bg-secondary-muted text-secondary',
  success: 'bg-green-500/10 text-green-400',
  danger: 'bg-red-500/10 text-red-400',
}

const sizes = {
  sm: 'px-2 py-0.5 text-xs',
  md: 'px-2.5 py-1 text-sm',
}

export function Badge({ children, variant = 'default', size = 'sm', className }: BadgeProps) {
  return (
    <span
      className={cn(
        'inline-flex items-center font-medium rounded-full whitespace-nowrap',
        variants[variant],
        sizes[size],
        className
      )}
    >
      {children}
    </span>
  )
}

import { cn } from '@/utils/cn'

interface SkeletonProps {
  className?: string
  variant?: 'text' | 'circular' | 'rectangular'
  width?: string | number
  height?: string | number
}

export function Skeleton({ className, variant = 'text', width, height }: SkeletonProps) {
  const base = 'animate-pulse bg-surface-border rounded-md'

  const variants = {
    text: 'h-4 w-full',
    circular: 'rounded-full',
    rectangular: 'h-24 w-full',
  }

  return (
    <div
      className={cn(base, variants[variant], className)}
      style={{ width, height }}
      aria-hidden="true"
    />
  )
}

export function CardSkeleton() {
  return (
    <div className="bg-surface border border-surface-border rounded-lg p-6 space-y-4">
      <Skeleton className="h-5 w-2/3" />
      <Skeleton className="h-4 w-full" />
      <Skeleton className="h-4 w-4/5" />
      <Skeleton className="h-3 w-1/3" />
    </div>
  )
}

export function TableSkeleton({ rows = 5 }: { rows?: number }) {
  return (
    <div className="space-y-3">
      {Array.from({ length: rows }).map((_, i) => (
        <Skeleton key={i} className="h-12 w-full" />
      ))}
    </div>
  )
}

import { cn } from '@/utils/cn'

interface ProgressProps {
  value: number
  max?: number
  size?: 'sm' | 'md'
  variant?: 'primary' | 'secondary'
  showLabel?: boolean
  className?: string
}

export function Progress({
  value,
  max = 100,
  size = 'md',
  variant = 'primary',
  showLabel = false,
  className,
}: ProgressProps) {
  const pct = Math.min(Math.max((value / max) * 100, 0), 100)

  return (
    <div className={cn('flex items-center gap-2', className)}>
      <div
        className={cn(
          'flex-1 bg-surface-border rounded-full overflow-hidden',
          size === 'sm' ? 'h-1.5' : 'h-2'
        )}
        role="progressbar"
        aria-valuenow={value}
        aria-valuemin={0}
        aria-valuemax={max}
      >
        <div
          className={cn(
            'h-full rounded-full transition-all duration-500 ease-out',
            variant === 'primary' ? 'bg-primary' : 'bg-secondary'
          )}
          style={{ width: `${pct}%` }}
        />
      </div>
      {showLabel && (
        <span className="font-mono text-xs text-text-secondary tabular-nums">
          {Math.round(pct)}%
        </span>
      )}
    </div>
  )
}

import { cn } from '@/utils/cn'
import { motion } from 'framer-motion'
import { Inbox, AlertTriangle, Loader2 } from 'lucide-react'

interface EmptyStateProps {
  title: string
  description?: string
  icon?: React.ReactNode
  action?: React.ReactNode
  className?: string
}

export function EmptyState({ title, description, icon, action, className }: EmptyStateProps) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 10 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.3 }}
      className={cn(
        'flex flex-col items-center justify-center py-16 px-4 text-center',
        className
      )}
    >
      <div className="mb-4 text-text-muted">
        {icon || <Inbox className="h-12 w-12" />}
      </div>
      <h3 className="text-lg font-display font-semibold text-text-primary mb-1">{title}</h3>
      {description && (
        <p className="text-sm text-text-secondary max-w-sm">{description}</p>
      )}
      {action && <div className="mt-6">{action}</div>}
    </motion.div>
  )
}

interface ErrorStateProps {
  title?: string
  message?: string
  onRetry?: () => void
  className?: string
}

export function ErrorState({
  title = 'Something went wrong',
  message = 'An unexpected error occurred. Please try again.',
  onRetry,
  className,
}: ErrorStateProps) {
  return (
    <div
      className={cn(
        'flex flex-col items-center justify-center py-16 px-4 text-center',
        className
      )}
    >
      <AlertTriangle className="h-12 w-12 text-danger mb-4" />
      <h3 className="text-lg font-display font-semibold text-text-primary mb-1">{title}</h3>
      <p className="text-sm text-text-secondary max-w-sm mb-6">{message}</p>
      {onRetry && (
        <button
          onClick={onRetry}
          className="px-4 py-2 text-sm font-medium text-primary hover:text-primary-hover bg-primary-muted rounded-md transition-colors"
        >
          Try again
        </button>
      )}
    </div>
  )
}

interface LoadingStateProps {
  message?: string
  className?: string
}

export function LoadingState({ message = 'Loading...', className }: LoadingStateProps) {
  return (
    <div
      className={cn(
        'flex flex-col items-center justify-center py-16 px-4',
        className
      )}
    >
      <Loader2 className="h-8 w-8 text-primary animate-spin mb-3" />
      <p className="text-sm text-text-secondary">{message}</p>
    </div>
  )
}

import { clsx, type ClassValue } from 'clsx'
import { twMerge } from 'tailwind-merge'

export function cn(...inputs: ClassValue[]) {
  return twMerge(clsx(inputs))
}

export function formatDate(date: string | Date): string {
  const d = typeof date === 'string' ? new Date(date) : date
  return d.toLocaleDateString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
  })
}

export function formatTime(minutes: number): string {
  if (minutes < 60) return `${minutes}m`
  const h = Math.floor(minutes / 60)
  const m = minutes % 60
  return m > 0 ? `${h}h ${m}m` : `${h}h`
}

export function truncate(str: string, length: number): string {
  if (str.length <= length) return str
  return str.slice(0, length) + '...'
}

