@import url('https://api.fontshare.com/v2/css?f[]=cabinet-grotesk@400,500,600,700&display=swap');

@import "tailwindcss";

@theme {
  /* Colors */
  --color-background: #0A0D12;
  --color-surface: #12161D;
  --color-surface-hover: #181D27;
  --color-surface-border: #1E2430;
  --color-primary: #1FBF9E;
  --color-primary-hover: #2AD4B2;
  --color-primary-muted: rgba(31, 191, 158, 0.1);
  --color-secondary: #E8A93B;
  --color-secondary-hover: #F0BC4E;
  --color-secondary-muted: rgba(232, 169, 59, 0.1);
  --color-text-primary: #E7EAF0;
  --color-text-secondary: #8A94A6;
  --color-text-muted: #5C6575;
  --color-text-inverse: #0A0D12;
  --color-danger: #EF4444;
  --color-danger-hover: #DC2626;
  --color-success: #22C55E;
  --color-warning: #E8A93B;
  --color-overlay: rgba(0, 0, 0, 0.6);

  /* Typography */
  --font-display: 'Cabinet Grotesk', 'Geist', 'Inter', sans-serif;
  --font-body: 'Inter', -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif;
  --font-mono: 'JetBrains Mono', 'Fira Code', monospace;

  /* Border Radius */
  --radius-sm: 8px;
  --radius-md: 12px;
  --radius-lg: 16px;
  --radius-xl: 20px;

  /* Shadows */
  --shadow-card: 0 1px 3px rgba(0, 0, 0, 0.3), 0 1px 2px rgba(0, 0, 0, 0.2);
  --shadow-elevated: 0 4px 6px rgba(0, 0, 0, 0.3), 0 2px 4px rgba(0, 0, 0, 0.2);
  --shadow-modal: 0 10px 25px rgba(0, 0, 0, 0.5), 0 4px 10px rgba(0, 0, 0, 0.3);
  --shadow-glow: 0 0 20px rgba(31, 191, 158, 0.15);
  --shadow-glow-secondary: 0 0 20px rgba(232, 169, 59, 0.15);

  /* Animation */
  --transition-fast: 150ms cubic-bezier(0.16, 1, 0.3, 1);
  --transition-normal: 200ms cubic-bezier(0.16, 1, 0.3, 1);
  --transition-slow: 300ms cubic-bezier(0.16, 1, 0.3, 1);
}

/* Light mode tokens (prepared for future) */
.light {
  --color-background: #F5F5F5;
  --color-surface: #FFFFFF;
  --color-surface-hover: #FAFAFA;
  --color-surface-border: #E5E5E5;
  --color-text-primary: #171717;
  --color-text-secondary: #737373;
  --color-text-muted: #A3A3A3;
  --color-text-inverse: #F5F5F5;
}

/* Base Styles */
body {
  font-family: var(--font-body);
  background-color: var(--color-background);
  color: var(--color-text-primary);
  -webkit-font-smoothing: antialiased;
  -moz-osx-font-smoothing: grayscale;
}

/* Scrollbar */
::-webkit-scrollbar {
  width: 6px;
  height: 6px;
}
::-webkit-scrollbar-track {
  background: transparent;
}
::-webkit-scrollbar-thumb {
  background: var(--color-surface-border);
  border-radius: 3px;
}
::-webkit-scrollbar-thumb:hover {
  background: var(--color-text-muted);
}

/* Focus visible */
*:focus-visible {
  outline: 2px solid var(--color-primary);
  outline-offset: 2px;
}

/* Selection */
::selection {
  background: var(--color-primary-muted);
  color: var(--color-primary);
}

@layer base {
  h1, h2, h3, h4, h5, h6 {
    font-family: var(--font-display);
    font-weight: 600;
    letter-spacing: -0.02em;
  }
}

