import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query'
import { apiClient } from '@/api/client'
import type {
  DashboardSummary,
  TopicProgress,
  Recommendation,
  LearningStreak,
  LearningPath,
  Lesson,
  LessonRequest,
  Quiz,
  QuizGenerateRequest,
  EvaluateRequest,
  EvaluateResult,
  SyllabusGraph,
  AdaptiveStatus,
  WeakConcepts,
  SessionData,
} from '@/types/learning'

// ─── Dashboard Hooks ──────────────────────────────────────────

export function useDashboard() {
  return useQuery<DashboardSummary>({
    queryKey: ['dashboard'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/dashboard')
      return data
    },
  })
}

export function useTopicProgress() {
  return useQuery<TopicProgress[]>({
    queryKey: ['dashboard', 'progress'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/dashboard/progress')
      return data
    },
  })
}

export function useRecommendations() {
  return useQuery<Recommendation[]>({
    queryKey: ['dashboard', 'recommendations'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/dashboard/recommendations')
      return data
    },
  })
}

export function useLearningStreak() {
  return useQuery<LearningStreak>({
    queryKey: ['dashboard', 'streak'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/dashboard/streak')
      return data
    },
  })
}

// ─── Knowledge Graph / Roadmap Hooks ──────────────────────────

export function useSyllabusGraph(syllabusId: string) {
  return useQuery<SyllabusGraph>({
    queryKey: ['knowledge-graph', syllabusId],
    queryFn: async () => {
      const { data } = await apiClient.get(`/api/v2/knowledge-graph/${syllabusId}`)
      return data
    },
    enabled: !!syllabusId,
  })
}

export function useLearningPath(
  syllabusTopicIds: string[],
  masteryScores: Record<string, number> = {},
  mode: string = 'standard'
) {
  return useQuery<LearningPath>({
    queryKey: ['learning-path', { syllabusTopicIds, masteryScores, mode }],
    queryFn: async () => {
      const { data } = await apiClient.post('/api/v2/knowledge-graph/learning-path', {
        syllabus_topic_ids: syllabusTopicIds,
        mastery_scores: masteryScores,
        mode,
      })
      return data
    },
    enabled: syllabusTopicIds.length > 0,
  })
}

// ─── Lesson Hooks ─────────────────────────────────────────────

export function useGenerateLesson() {
  return useMutation({
    mutationFn: async (request: LessonRequest) => {
      const { data } = await apiClient.post<Lesson>('/api/v2/lessons/lesson', request)
      return data
    },
  })
}

// ─── Quiz Hooks ───────────────────────────────────────────────

export function useGenerateQuiz() {
  return useMutation({
    mutationFn: async (request: QuizGenerateRequest) => {
      const { data } = await apiClient.post<Quiz>('/api/v2/quiz/generate', request)
      return data
    },
  })
}

export function useEvaluateQuiz() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (request: EvaluateRequest) => {
      const { data } = await apiClient.post<EvaluateResult>('/api/v2/quiz/evaluate', request)
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['dashboard'] })
    },
  })
}

// ─── Adaptive Hooks ───────────────────────────────────────────

export function useAdaptiveStatus() {
  return useQuery<AdaptiveStatus>({
    queryKey: ['adaptive', 'status'],
    queryFn: async () => {
      const { data } = await apiClient.get('/api/v2/adaptive/status')
      return data
    },
  })
}

export function useWeakConcepts(
  masteryScores: Record<string, number>,
  currentTopicId?: string
) {
  return useQuery<WeakConcepts>({
    queryKey: ['adaptive', 'weak-concepts', { masteryScores, currentTopicId }],
    queryFn: async () => {
      const { data } = await apiClient.post('/api/v2/knowledge-graph/weak-concepts', {
        mastery_scores: masteryScores,
        current_topic_id: currentTopicId,
      })
      return data
    },
    enabled: Object.keys(masteryScores).length > 0,
  })
}

// ─── Session Hooks ────────────────────────────────────────────

export function useCreateSession() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (params: { syllabus_id?: string; session_id?: string; metadata?: Record<string, unknown> }) => {
      const { data } = await apiClient.post<SessionData>('/api/v2/sessions', params)
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['sessions'] })
    },
  })
}

export function useSession(sessionId: string) {
  return useQuery<SessionData>({
    queryKey: ['sessions', sessionId],
    queryFn: async () => {
      const { data } = await apiClient.get(`/api/v2/sessions/${sessionId}`)
      return data
    },
    enabled: !!sessionId,
  })
}

export function useCompleteSession() {
  const queryClient = useQueryClient()
  return useMutation({
    mutationFn: async (sessionId: string) => {
      const { data } = await apiClient.post(`/api/v2/sessions/${sessionId}/complete`)
      return data
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['sessions'] })
      queryClient.invalidateQueries({ queryKey: ['dashboard'] })
    },
  })
}

import { createContext, useContext, useState, useEffect, useCallback, type ReactNode } from 'react'
import { authApi } from '@/api'
import type { User, AuthTokens, LoginPayload, RegisterPayload } from '@/types'

interface AuthContextType {
  user: User | null
  isAuthenticated: boolean
  isLoading: boolean
  login: (payload: LoginPayload) => Promise<void>
  register: (payload: RegisterPayload) => Promise<void>
  logout: () => Promise<void>
}

const AuthContext = createContext<AuthContextType | null>(null)

function getStoredTokens(): AuthTokens | null {
  try {
    const stored = localStorage.getItem('aaa_auth_tokens')
    return stored ? JSON.parse(stored) : null
  } catch {
    return null
  }
}

function getStoredUser(): User | null {
  try {
    const stored = localStorage.getItem('aaa_user')
    return stored ? JSON.parse(stored) : null
  } catch {
    return null
  }
}

export function AuthProvider({ children }: { children: ReactNode }) {
  const [user, setUser] = useState<User | null>(getStoredUser)
  const [isLoading, setIsLoading] = useState(true)

  const isAuthenticated = !!user && !!getStoredTokens()

  const login = useCallback(async (payload: LoginPayload) => {
    const { user: userData, tokens } = await authApi.login(payload)
    localStorage.setItem('aaa_auth_tokens', JSON.stringify(tokens))
    localStorage.setItem('aaa_user', JSON.stringify(userData))
    setUser(userData)
  }, [])

  const register = useCallback(async (payload: RegisterPayload) => {
    await authApi.register(payload)
  }, [])

  const logout = useCallback(async () => {
    try {
      await authApi.logout()
    } catch {
      // Ignore server errors on logout
    }
    localStorage.removeItem('aaa_auth_tokens')
    localStorage.removeItem('aaa_user')
    setUser(null)
  }, [])

  // Verify session on mount
  useEffect(() => {
    const verify = async () => {
      const tokens = getStoredTokens()
      if (!tokens) {
        setIsLoading(false)
        return
      }
      try {
        const userData = await authApi.me()
        localStorage.setItem('aaa_user', JSON.stringify(userData))
        setUser(userData)
      } catch {
        localStorage.removeItem('aaa_auth_tokens')
        localStorage.removeItem('aaa_user')
        setUser(null)
      } finally {
        setIsLoading(false)
      }
    }
    verify()
  }, [])

  return (
    <AuthContext.Provider value={{ user, isAuthenticated, isLoading, login, register, logout }}>
      {children}
    </AuthContext.Provider>
  )
}

export function useAuth() {
  const ctx = useContext(AuthContext)
  if (!ctx) {
    throw new Error('useAuth must be used within an AuthProvider')
  }
  return ctx
}

import { type ReactNode } from 'react'
import { cn } from '@/utils/cn'

interface CardProps {
  children: ReactNode
  className?: string
  hover?: boolean
  padding?: 'sm' | 'md' | 'lg'
}

const paddings = {
  sm: 'p-4',
  md: 'p-6',
  lg: 'p-8',
}

export function Card({ children, className, hover = false, padding = 'md' }: CardProps) {
  return (
    <div
      className={cn(
        'bg-surface border border-surface-border rounded-lg shadow-card transition-all duration-200',
        hover && 'hover:border-primary/30 hover:shadow-glow cursor-pointer',
        paddings[padding],
        className
      )}
    >
      {children}
    </div>
  )
}

import { cn } from '@/utils/cn'
import { type ReactNode } from 'react'

interface AvatarProps {
  src?: string
  alt?: string
  name?: string
  size?: 'sm' | 'md' | 'lg'
  className?: string
}

const sizes = {
  sm: 'h-8 w-8 text-xs',
  md: 'h-10 w-10 text-sm',
  lg: 'h-12 w-12 text-base',
}

function getInitials(name: string): string {
  return name
    .split(' ')
    .map((n) => n[0])
    .join('')
    .toUpperCase()
    .slice(0, 2)
}

export function Avatar({ src, alt, name, size = 'md', className }: AvatarProps) {
  if (src) {
    return (
      <img
        src={src}
        alt={alt || name || 'Avatar'}
        className={cn('rounded-full object-cover', sizes[size], className)}
      />
    )
  }

  return (
    <div
      className={cn(
        'rounded-full bg-primary-muted text-primary font-medium flex items-center justify-center',
        sizes[size],
        className
      )}
      aria-label={alt || name || 'Avatar'}
    >
      {name ? getInitials(name) : <UserIcon />}
    </div>
  )
}

function UserIcon() {
  return (
    <svg width="16" height="16" viewBox="0 0 16 16" fill="none" stroke="currentColor" strokeWidth="1.5">
      <circle cx="8" cy="5" r="3" />
      <path d="M2 14c0-3.3 2.7-6 6-6s6 2.7 6 6" />
    </svg>
  )
}

// -- StatCard --

interface StatCardProps {
  label: string
  value: string | number
  icon?: ReactNode
  trend?: 'up' | 'down'
  trendValue?: string
  variant?: 'primary' | 'secondary'
}

export function StatCard({ label, value, icon, trend, trendValue, variant = 'primary' }: StatCardProps) {
  return (
