        {icon && (
          <span className={cn(variant === 'primary' ? 'text-primary' : 'text-secondary')}>
            {icon}
          </span>
        )}
      </div>
      <div className="flex items-end gap-2">
        <span className="font-display text-2xl font-semibold text-text-primary tabular-nums">
          {value}
        </span>
        {trend && trendValue && (
          <span
