              </Card>

              {/* ── Learning mode selector (visual placeholder) ──── */}
              <Card padding="sm" className="bg-[#12161D] border-[#1E2430]">
                <h3 className="text-sm font-display font-semibold text-[#E7EAF0] mb-3">
