import { useState, useCallback, useEffect } from 'react'
import { useParams, useNavigate, Link } from 'react-router-dom'
import { motion, AnimatePresence } from 'framer-motion'
import { Card, Button, Badge, Progress, Skeleton } from '@/components/ui'
import { EmptyState, ErrorState, LoadingState } from '@/components/ui'
import { useGenerateQuiz } from '@/services/learningApi'
import {
  BookOpen,
  Clock,
  ArrowLeft,
  ArrowRight,
  CheckCircle,
  XCircle,
  HelpCircle,
  List,
  BarChart3,
  ChevronLeft,
  ChevronRight,
  Flag,
  Send,
  Loader2,
} from 'lucide-react'
import { cn } from '@/utils/cn'
import type { QuizQuestion } from '@/types/learning'

// ─── Types ─────────────────────────────────────────────────────────────────

interface AnswerEntry {
  questionId: string
  selectedAnswer: string
}

// ─── Animation Variants ─────────────────────────────────────────────────────

const PAGE_VARIANTS = {
  hidden: { opacity: 0 },
  visible: {
    opacity: 1,
    transition: { duration: 0.3, when: 'beforeChildren', staggerChildren: 0.06 },
  },
}

const CARD_VARIANTS = {
  hidden: { opacity: 0, y: 20 },
  visible: { opacity: 1, y: 0, transition: { duration: 0.35, ease: 'easeOut' } },
  exit: { opacity: 0, y: -20, transition: { duration: 0.2 } },
}

const OPTION_VARIANTS = {
  hidden: { opacity: 0, x: -12 },
  visible: (i: number) => ({
    opacity: 1,
    x: 0,
    transition: { delay: 0.1 + i * 0.05, duration: 0.25, ease: 'easeOut' },
  }),
}

// ─── Helpers ────────────────────────────────────────────────────────────────

function getDifficultyColor(difficulty: string): 'primary' | 'secondary' | 'default' {
  switch (difficulty.toLowerCase()) {
    case 'beginner':
      return 'success'
    case 'intermediate':
      return 'secondary'
    case 'advanced':
      return 'danger'
    default:
      return 'default'
  }
}

function getDifficultyLabel(difficulty: string): string {
  switch (difficulty.toLowerCase()) {
    case 'beginner':
      return 'Beginner'
    case 'intermediate':
      return 'Intermediate'
    case 'advanced':
      return 'Advanced'
    default:
      return difficulty
  }
}

// ─── Sub-components ─────────────────────────────────────────────────────────

function QuizHeaderSkeleton() {
  return (
    <div className="flex flex-col gap-4 mb-8">
      <div className="flex items-center justify-between">
        <Skeleton className="h-8 w-48" />
        <Skeleton className="h-9 w-24" />
      </div>
      <div className="flex items-center gap-4">
        <Skeleton className="h-5 w-32" />
        <Skeleton className="h-5 w-20" />
      </div>
      <Skeleton className="h-2 w-full" />
    </div>
  )
}

function QuestionSkeleton() {
  return (
    <Card className="max-w-2xl mx-auto">
      <div className="space-y-6">
        <div className="flex items-center gap-3">
          <Skeleton className="h-6 w-24 rounded-full" />
          <Skeleton className="h-6 w-28 rounded-full" />
          <Skeleton className="h-6 w-20 rounded-full" />
        </div>
        <Skeleton className="h-8 w-full" />
        <Skeleton className="h-8 w-4/5" />
        <div className="space-y-3 pt-4">
          {[0, 1, 2, 3].map((i) => (
            <Skeleton key={i} className="h-14 w-full rounded-lg" />
          ))}
        </div>
      </div>
    </Card>
  )
}

// ─── Main Component ─────────────────────────────────────────────────────────

export function QuizPage() {
  const { topicId } = useParams<{ topicId: string }>()
  const navigate = useNavigate()

  const generateQuiz = useGenerateQuiz()

  const [quiz, setQuiz] = useState<{ topicName: string; questions: QuizQuestion[] } | null>(null)
  const [answers, setAnswers] = useState<Map<string, string>>(new Map())
  const [currentQuestionIndex, setCurrentQuestionIndex] = useState(0)
  const [error, setError] = useState<string | null>(null)
  const [isSubmitting, setIsSubmitting] = useState(false)

  // ── Generate quiz on mount ──────────────────────────────────────────────

  const fetchQuiz = useCallback(async () => {
    if (!topicId) return
    setError(null)
    try {
      const result = await generateQuiz.mutateAsync({
        topic_id: topicId,
        topic_name: '',
        num_questions: 10,
      })
      setQuiz({
        topicName: result.topic_name,
        questions: result.questions,
      })
      setAnswers(new Map())
      setCurrentQuestionIndex(0)
    } catch (err) {
      setError(err instanceof Error ? err.message : 'Failed to generate quiz')
    }
  }, [topicId, generateQuiz])

  useEffect(() => {
    fetchQuiz()
  }, [fetchQuiz])

  // ── Derived state ────────────────────────────────────────────────────────

  const questions = quiz?.questions ?? []
  const totalQuestions = questions.length
  const currentQuestion = questions[currentQuestionIndex] ?? null
  const answeredCount = answers.size
  const allAnswered = answeredCount === totalQuestions && totalQuestions > 0
  const answeredQuestions = new Set(answers.keys())

  // ── Answer handlers ──────────────────────────────────────────────────────

  const selectAnswer = useCallback(
    (questionId: string, option: string) => {
      setAnswers((prev) => {
        const next = new Map(prev)
        next.set(questionId, option)
        return next
      })
    },
    []
  )

  const goToQuestion = useCallback((index: number) => {
    if (index >= 0 && index < totalQuestions) {
      setCurrentQuestionIndex(index)
    }
  }, [totalQuestions])

  const goNext = useCallback(() => {
    if (currentQuestionIndex < totalQuestions - 1) {
      setCurrentQuestionIndex((prev) => prev + 1)
    }
  }, [currentQuestionIndex, totalQuestions])

  const goPrevious = useCallback(() => {
    if (currentQuestionIndex > 0) {
      setCurrentQuestionIndex((prev) => prev - 1)
    }
  }, [currentQuestionIndex])

  // ── Keyboard navigation ──────────────────────────────────────────────────

  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent) {
      // Number keys 1-4 for option selection
      if (currentQuestion && ['1', '2', '3', '4'].includes(e.key)) {
        const idx = parseInt(e.key, 10) - 1
        if (idx < currentQuestion.options.length) {
          selectAnswer(currentQuestion.id, currentQuestion.options[idx])
        }
      }
      // Arrow keys for navigation
      if (e.key === 'ArrowRight') goNext()
      if (e.key === 'ArrowLeft') goPrevious()
    }
    window.addEventListener('keydown', handleKeyDown)
    return () => window.removeEventListener('keydown', handleKeyDown)
  }, [currentQuestion, selectAnswer, goNext, goPrevious])

  // ── Submit handler ───────────────────────────────────────────────────────

  const handleSubmit = useCallback(() => {
    if (!quiz || !allAnswered || isSubmitting) return
    setIsSubmitting(true)

    const submissionData = {
      topicId: topicId!,
      topicName: quiz.topicName,
      questions: quiz.questions,
      answers: Array.from(answers.entries()).map(([questionId, selectedAnswer]) => ({
        questionId,
        selectedAnswer,
      })),
    }

    navigate(`/quiz-results/${topicId}`, { state: submissionData })
  }, [quiz, topicId, answers, allAnswered, isSubmitting, navigate])

  // ── Render: Loading ──────────────────────────────────────────────────────

  if (generateQuiz.isPending) {
    return (
      <div className="min-h-screen bg-background" role="status" aria-label="Loading quiz">
        <div className="max-w-6xl mx-auto px-4 py-8">
          <QuizHeaderSkeleton />
          <QuestionSkeleton />
        </div>
      </div>
    )
  }

  // ── Render: Error ────────────────────────────────────────────────────────

  if (error || generateQuiz.isError) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <ErrorState
          title="Failed to load quiz"
          message={error || generateQuiz.error?.message || 'Unable to generate quiz questions. Please try again.'}
          onRetry={fetchQuiz}
        />
      </div>
    )
  }

  // ── Render: Empty ────────────────────────────────────────────────────────

  if (!quiz || questions.length === 0) {
    return (
      <div className="min-h-screen bg-background flex items-center justify-center">
        <EmptyState
          title="No quiz available"
          description="No questions could be generated for this topic. Please try again later."
          icon={<BookOpen className="h-12 w-12" />}
          action={
            <Button variant="secondary" onClick={fetchQuiz} loading={generateQuiz.isPending}>
              Try Again
            </Button>
          }
        />
      </div>
    )
  }

  // ── Render: Quiz ─────────────────────────────────────────────────────────

  return (
    <div className="min-h-screen bg-background">
      <div className="max-w-6xl mx-auto px-4 py-6 lg:py-8">
        {/* ── Quiz Header ───────────────────────────────────────────────── */}
        <motion.div
          initial={{ opacity: 0, y: -8 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.3 }}
          className="mb-6 space-y-4"
        >
          <div className="flex items-center justify-between flex-wrap gap-3">
            <div className="flex items-center gap-3">
              <Button
                variant="ghost"
                size="sm"
                onClick={() => navigate(-1)}
                aria-label="Go back"
              >
                <ArrowLeft className="h-4 w-4" />
                Back
              </Button>
              <h1 className="text-xl lg:text-2xl font-display font-bold text-text-primary">
                {quiz.topicName} Quiz
              </h1>
            </div>

            <div className="flex items-center gap-4 text-text-muted">
              <div className="flex items-center gap-1.5 text-sm" aria-label="Quiz timer">
                <Clock className="h-4 w-4" />
                <span className="font-mono tabular-nums">--:--</span>
              </div>
              <div className="hidden sm:flex items-center gap-1.5 text-sm text-text-secondary">
                <List className="h-4 w-4" />
                <span>{answeredCount}/{totalQuestions}</span>
              </div>
            </div>
          </div>

          {/* Progress bar */}
